class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        int base_time = time[0];
        int mul_sum = 0;
        for (int i = 1; i < n; i++) {
            base_time += time[i];
            mul_sum += mul[i];
        }
        int return_time = base_time;
        for (int i = 0; i < k; i++) {
            return_time = min(return_time, base_time + mul_sum * time[i]);
        }
        return return_time;
    }
};
